const msg = $input.item.json.message || {};
const text = (msg.text || '').trim();
const chatId = msg.chat?.id;

// Mapa de procesos disparables manualmente. 'q10' usa la cadena existente del bot.
const PROCESOS = {
  q10:        { comando: null, nombre: 'Q10 → Sheets + Dashboard' },
  panel:      { comando: 'cd C:/Users/EstudiantesJC/downloads/admin-usable/scripts/panel-datos && python normalize_q10_data.py && python cargar_supabase.py && python sync_aprobacion_supabase.py && python sync_emoflow_api.py && python export_supabase_json.py && python sync_supabase_to_sheets.py', nombre: 'Pipeline Panel de Datos → Supabase' },
  asistencia: { comando: 'cd C:/Users/EstudiantesJC/downloads/admin-usable && python scripts/panel-datos/sync_asistencia_supabase.py && python scripts/panel-datos/calcular_asistencia_promedio.py', nombre: 'Asistencia Zoom → Supabase' },
  mr:         { comando: 'cd C:/Users/EstudiantesJC/Downloads/Admin-usable/scripts/mr-actualizacion-datos && python actualizar_bd_mr.py', nombre: 'Form MR2024 → BD Mujeres ROFÉ' },
  rebotes:    { comando: 'cd C:/Users/EstudiantesJC/Downloads/Admin-usable && python scripts/mujeres-rofe-correos/capturar_rebotes.py', nombre: 'Captura rebotes de correo' },
  alerta:     { comando: 'cd C:/Users/EstudiantesJC/Downloads/Admin-usable && python scripts/panel-datos/alerta_desercion.py --csv', nombre: 'Alerta de deserción' },
  backfill:   { comando: 'cd /d C:\\Users\\EstudiantesJC\\downloads\\admin-usable && python scripts\\zoom-youtube\\backfill_grabaciones.py --dias 2', nombre: 'Backfill grabaciones Zoom → YouTube/Drive' },
};

const m = text.match(/^\/actualizar\s+(\w+)$/i);
const proceso = m ? m[1].toLowerCase() : null;
const valido = proceso !== null && Object.prototype.hasOwnProperty.call(PROCESOS, proceso);

return [{ json: {
  valido,
  proceso: valido ? proceso : null,
  comando: valido ? PROCESOS[proceso].comando : null,
  nombre: valido ? PROCESOS[proceso].nombre : null,
  chat_id: chatId,
  texto_original: text
}}];

