  const stderr = $('Ejecutar organizador').first().json.stderr || $('Ejecutar organizador').first().json.stdout || 'Sin detalle disponible.';
  return '\u274C Error en el organizador\n\n' + stderr.slice(0, 400);
})() }}

={{ (() => {
  const stdoutQ10 = $('Ejecutar q10_to_sheets').first().json.stdout || '';
  const stdoutOrg = $('Ejecutar organizador').first().json.stdout || '';
  const stdoutRet = $('Organizar retirados').first().json.stdout || '';
  const mQ10 = stdoutQ10.match(/RESUMEN: grupo=\S+ filas=(\d+) estado=exito/);
  const mOrg = stdoutOrg.match(/RESUMEN: cursos=(\d+) estudiantes=(\d+) habilitados=(\d+) promedio=([\d.]+)/);
  const mRet = stdoutRet.match(/RESUMEN: retirados=(\d+) cancelados=(\d+) desertores=(\d+) aplazados=(\d+)/);
  const filasQ10    = mQ10 ? mQ10[1] : '?';
  const cursos      = mOrg ? mOrg[1] : '?';
  const estudiantes = mOrg ? mOrg[2] : '?';
  const habilitados = mOrg ? mOrg[3] : '?';
  const promedio    = mOrg ? mOrg[4] : '?';
  const retirados   = mRet ? mRet[1] : '?';
  const cancelados  = mRet ? mRet[2] : '?';
  const statsOk  = $('Ejecutar export_stats').first().json.exitCode === 0;
  const avanceOk = $('Ejecutar export_avance').first().json.exitCode === 0;
  const retOk    = $('Ejecutar export_retirados').first().json.exitCode === 0;
  const aprobOk  = $('Ejecutar export_aprobacion').first().json.exitCode === 0;
  const mAprob   = ($('Ejecutar export_aprobacion').first().json.stdout || '').match(/EXPORT: cursos=\d+ matriculas=(\d+) aprobados=(\d+) estado=exito/);
  const pctAprob = mAprob ? (100 * mAprob[2] / mAprob[1]).toFixed(1) + '%' : '?';
  const sinCompOk = $json.exitCode === 0;
  const mSinComp  = ($json.stdout || '').match(/RESUMEN: cursos=\d+ matriculas_sin_completar=(\d+) ciudades=(\d+) sin_ubicacion=\d+ estado=exito/);
  const nSinComp  = mSinComp ? mSinComp[1] : '?';
  const nCiudades = mSinComp ? mSinComp[2] : '?';
  const ok = (v) => v ? '\u2705' : '\u26A0\uFE0F';
  return '\u2705 Q10 actualizado\n\n' +
    '\ud83d\udce5 Filas Q10: ' + filasQ10 + '\n' +
    '\ud83d\udcca Cursos: ' + cursos + ' | Activos: ' + habilitados + ' | Total: ' + estudiantes + ' | Prom: ' + promedio + '%\n' +
    '\ud83d\udeaa Retirados: ' + retirados + ' (' + cancelados + ' cancelados)\n' +
    ok(statsOk) + ' Stats \u2192 GitHub Pages\n' +
    ok(avanceOk) + ' Avance \u2192 GitHub Pages\n' +
    ok(retOk) + ' Retirados \u2192 GitHub Pages\n' +
    ok(aprobOk) + ' Aprobaci\u00f3n \u2192 GitHub Pages (' + pctAprob + ' aprob\u00f3)\n' +
    ok(sinCompOk) + ' Sin completar \u2192 Sheet (' + nSinComp + ' en ' + nCiudades + ' ciudades)\n' +
    '\n\ud83c\udf10 fundacion-rofe.github.io/Estadisticas/dashboard/';
})() }}

={{ (() => {
  const nombre = $('Parsear Comando').first().json.nombre;
  const exit = $json.exitCode !== undefined ? $json.exitCode : -1;
  const ok = exit === 0;
  const salida = ((ok ? ($json.stdout || '') : (($json.stderr || '') || ($json.stdout || ''))).trim()).slice(-800);
  return (ok ? '\u2705 ' : '\u26a0\ufe0f ') + nombre + (ok ? ' — completado' : ' — ERROR (exit ' + exit + ')') + (salida ? '\n\n' + salida : '');
})() }}

